// lib/features/share/providers/share_provider.dart
//
// DAXELO KINREL — Share & Invite Provider
//
// Manages invite links, kinship share cards, and family graph export.
// Supports 6 invite methods: Link, QR Code, WhatsApp, SMS, Email, Copy.
// Kinship share card displays the regional term, English translation,
// relationship path, and "Generated by Kinrel" branding.
// Family graph export with watermark.
//
// Orange K-Graph DNA: Link=orange, QR=amber, WhatsApp=green,
//   SMS=blue, Email=orange, Copy=white.

import 'package:flutter_riverpod/flutter_riverpod.dart';

// ═══════════════════════════════════════════════════════════════════════
// Invite Method Enum
// ═══════════════════════════════════════════════════════════════════════

/// Methods available for sharing an invite.
enum InviteMethod {
  link,
  qrCode,
  whatsapp,
  sms,
  email,
  copyLink,
}

// ═══════════════════════════════════════════════════════════════════════
// Invite Link Model
// ═══════════════════════════════════════════════════════════════════════

/// Represents an active invite link for a family.
class InviteLink {
  const InviteLink({
    required this.id,
    required this.code,
    required this.familyId,
    required this.familyName,
    required this.createdAt,
    required this.expiresAt,
    this.usedCount = 0,
    this.maxUses = 50,
    this.isActive = true,
  });

  /// Unique identifier.
  final String id;

  /// Short alphanumeric invite code (e.g. "abc123").
  final String code;

  /// The family this link belongs to.
  final String familyId;

  /// Display name of the family.
  final String familyName;

  /// When the link was created.
  final DateTime createdAt;

  /// When the link expires.
  final DateTime expiresAt;

  /// Number of times the link has been used.
  final int usedCount;

  /// Maximum allowed uses.
  final int maxUses;

  /// Whether the link is still active.
  final bool isActive;

  // ── Computed Properties ──────────────────────────────────────────

  /// Full deep link URL (e.g., kinrel.app/invite/abc123).
  String get deepLink => 'kinrel.app/invite/$code';

  /// Whether the link has expired.
  bool get isExpired => DateTime.now().isAfter(expiresAt);

  /// Days remaining until expiry.
  int get daysUntilExpiry => expiresAt.difference(DateTime.now()).inDays;

  /// Formatted expiry label.
  String get expiryLabel {
    if (isExpired) return 'Expired';
    if (daysUntilExpiry == 0) return 'Expires today';
    if (daysUntilExpiry == 1) return 'Expires tomorrow';
    return 'Expires in $daysUntilExpiry days';
  }

  /// Usage label.
  String get usageLabel => '$usedCount / $maxUses used';

  /// Formatted creation date.
  String get formattedCreatedDate {
    const months = [
      '', 'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
      'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
    ];
    return '${createdAt.day} ${months[createdAt.month]} ${createdAt.year}';
  }

  /// WhatsApp pre-formatted message.
  String get whatsappMessage =>
      'Hey! Join our family on Kinrel 🧡\n\n'
      'I\'m building our family tree and I\'d love for you to be part of it. '
      'Click the link below to join the *$familyName* family:\n\n'
      '🔗 $deepLink\n\n'
      '— Sent via Kinrel by Daxelo';

  /// SMS pre-formatted message.
  String get smsMessage =>
      'Join our family on Kinrel! Click here: $deepLink — Sent via Kinrel';

  /// Email subject line.
  String get emailSubject => 'Join the $familyName Family on Kinrel';

  /// Email body.
  String get emailBody =>
      'Hi there!\n\n'
      'I\'m building our family tree on Kinrel and would love for you to join.\n\n'
      'Click the link below to join the $familyName family:\n'
      '$deepLink\n\n'
      'With Kinrel, you can:\n'
      '• Discover how you\'re related to family members\n'
      '• Learn kinship terms in your regional language\n'
      '• Build and explore your family graph\n\n'
      'Looking forward to connecting!\n\n'
      '— Sent via Kinrel by Daxelo';

  InviteLink copyWith({
    String? id,
    String? code,
    String? familyId,
    String? familyName,
    DateTime? createdAt,
    DateTime? expiresAt,
    int? usedCount,
    int? maxUses,
    bool? isActive,
  }) {
    return InviteLink(
      id: id ?? this.id,
      code: code ?? this.code,
      familyId: familyId ?? this.familyId,
      familyName: familyName ?? this.familyName,
      createdAt: createdAt ?? this.createdAt,
      expiresAt: expiresAt ?? this.expiresAt,
      usedCount: usedCount ?? this.usedCount,
      maxUses: maxUses ?? this.maxUses,
      isActive: isActive ?? this.isActive,
    );
  }
}

// ═══════════════════════════════════════════════════════════════════════
// Kinship Share Card Model
// ═══════════════════════════════════════════════════════════════════════

/// A shareable kinship card showing the regional term, translation,
/// and relationship path.
class KinshipShareCard {
  const KinshipShareCard({
    required this.id,
    required this.personName,
    required this.kinshipTermRegional,
    required this.kinshipTermEnglish,
    required this.relationshipPath,
    this.languageName = 'Hindi',
    this.languageScript = 'हिंदी',
    this.generationNumber = 2,
  });

  /// Unique identifier.
  final String id;

  /// Name of the person you call by this kinship term.
  final String personName;

  /// The kinship term in regional script (e.g., "चाचा").
  final String kinshipTermRegional;

  /// English translation (e.g., "Father's younger brother").
  final String kinshipTermEnglish;

  /// Human-readable relationship path (e.g., "You → Father → Younger Brother").
  final String relationshipPath;

  /// Name of the language (e.g., "Hindi").
  final String languageName;

  /// Script name in native form (e.g., "हिंदी").
  final String languageScript;

  /// Which generation this relative belongs to.
  final int generationNumber;

  // ── Computed Properties ──────────────────────────────────────────

  /// "What do I call [name]?" question text.
  String get questionText => 'What do I call $personName?';

  /// Share text for WhatsApp Status.
  String get whatsappStatusText =>
      'I call them *$kinshipTermRegional* ($kinshipTermEnglish) 🧡\n\n'
      '$questionText\n'
      'Path: $relationshipPath\n\n'
      '#Kinrel #Family #Kinship';

  /// Share text for general share sheet.
  String get shareText =>
      'On Kinrel, I discovered I call $personName "$kinshipTermRegional" '
      '($kinshipTermEnglish).\n\n'
      'Path: $relationshipPath\n\n'
      '— Generated by Kinrel';

  KinshipShareCard copyWith({
    String? id,
    String? personName,
    String? kinshipTermRegional,
    String? kinshipTermEnglish,
    String? relationshipPath,
    String? languageName,
    String? languageScript,
    int? generationNumber,
  }) {
    return KinshipShareCard(
      id: id ?? this.id,
      personName: personName ?? this.personName,
      kinshipTermRegional: kinshipTermRegional ?? this.kinshipTermRegional,
      kinshipTermEnglish: kinshipTermEnglish ?? this.kinshipTermEnglish,
      relationshipPath: relationshipPath ?? this.relationshipPath,
      languageName: languageName ?? this.languageName,
      languageScript: languageScript ?? this.languageScript,
      generationNumber: generationNumber ?? this.generationNumber,
    );
  }
}

