// Share Tab Enum
// ═══════════════════════════════════════════════════════════════════════

/// Tabs on the Share screen.
enum ShareTab {
  invite,
  shareCard,
  shareGraph,
}

// ═══════════════════════════════════════════════════════════════════════
// Share State
// ═══════════════════════════════════════════════════════════════════════

/// State for the Share & Invite feature.
class ShareState {
  const ShareState({
    this.inviteLinks = const [],
    this.kinshipCards = const [],
    this.currentTab = ShareTab.invite,
    this.familyId = '',
    this.familyName = '',
    this.isExporting = false,
    this.copiedToClipboard = false,
  });

  /// Active invite links for the family.
  final List<InviteLink> inviteLinks;

  /// Available kinship share cards.
  final List<KinshipShareCard> kinshipCards;

  /// Currently selected tab.
  final ShareTab currentTab;

  /// Family ID for context.
  final String familyId;

  /// Family display name.
  final String familyName;

  /// Whether a graph export is in progress.
  final bool isExporting;

  /// Whether link was recently copied to clipboard.
  final bool copiedToClipboard;

  /// Active (non-expired) invite links.
  List<InviteLink> get activeLinks =>
      inviteLinks.where((l) => l.isActive && !l.isExpired).toList();

  /// Expired invite links.
  List<InviteLink> get expiredLinks =>
      inviteLinks.where((l) => l.isExpired || !l.isActive).toList();

  /// Primary invite link (most recent active).
  InviteLink? get primaryLink =>
      activeLinks.isNotEmpty ? activeLinks.first : null;

  ShareState copyWith({
    List<InviteLink>? inviteLinks,
    List<KinshipShareCard>? kinshipCards,
    ShareTab? currentTab,
    String? familyId,
    String? familyName,
    bool? isExporting,
    bool? copiedToClipboard,
  }) {
    return ShareState(
      inviteLinks: inviteLinks ?? this.inviteLinks,
      kinshipCards: kinshipCards ?? this.kinshipCards,
      currentTab: currentTab ?? this.currentTab,
      familyId: familyId ?? this.familyId,
      familyName: familyName ?? this.familyName,
      isExporting: isExporting ?? this.isExporting,
      copiedToClipboard: copiedToClipboard ?? this.copiedToClipboard,
    );
  }
}

// ═══════════════════════════════════════════════════════════════════════
// Share Notifier
// ═══════════════════════════════════════════════════════════════════════

/// State notifier managing share & invite operations.
class ShareNotifier extends StateNotifier<ShareState> {
  ShareNotifier({required String familyId, required String familyName})
      : super(ShareState(
          familyId: familyId,
          familyName: familyName,
          inviteLinks: _demoInviteLinks,
          kinshipCards: _demoKinshipCards,
        ));

  /// Switch between tabs.
  void setTab(ShareTab tab) {
    state = state.copyWith(currentTab: tab);
  }

  /// Generate a new invite link.
  void generateLink() {
    final code = _generateCode();
    final now = DateTime.now();
    final newLink = InviteLink(
      id: 'link-${now.millisecondsSinceEpoch}',
      code: code,
      familyId: state.familyId,
      familyName: state.familyName,
      createdAt: now,
      expiresAt: now.add(const Duration(days: 30)),
      usedCount: 0,
      maxUses: 50,
      isActive: true,
    );
    state = state.copyWith(inviteLinks: [newLink, ...state.inviteLinks]);
  }

  /// Deactivate an invite link.
  void deactivateLink(String linkId) {
    final updated = state.inviteLinks.map((l) {
      if (l.id == linkId) return l.copyWith(isActive: false);
      return l;
    }).toList();
    state = state.copyWith(inviteLinks: updated);
  }

  /// Mark link as copied to clipboard.
  void markCopied() {
    state = state.copyWith(copiedToClipboard: true);
    // Reset after 2 seconds
    Future.delayed(const Duration(seconds: 2), () {
      if (mounted) state = state.copyWith(copiedToClipboard: false);
    });
  }

  /// Start graph export simulation.
  Future<void> exportGraph() async {
    state = state.copyWith(isExporting: true);
    // Simulate export delay
    await Future.delayed(const Duration(seconds: 2));
    if (mounted) state = state.copyWith(isExporting: false);
  }

  /// Generate a random 6-char invite code.
  static String _generateCode() {
    const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
    final now = DateTime.now().millisecondsSinceEpoch;
    // Simple deterministic "random" from timestamp
    return List.generate(6, (i) {
      final index = (now + i * 7) % chars.length;
      return chars[index];
    }).join();
  }
}

// ═══════════════════════════════════════════════════════════════════════
// Provider
// ═══════════════════════════════════════════════════════════════════════

/// Family-scoped share provider.
/// Usage: ref.watch(shareProvider(familyId: 'xxx', familyName: 'Sharma'))
final shareProvider = StateNotifierProvider.family<ShareNotifier, ShareState,
    ({String familyId, String familyName})>(
  (ref, params) => ShareNotifier(
    familyId: params.familyId,
    familyName: params.familyName,
  ),
);

